output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?year WHERE {
  wd:Q1344202 wdt:P577 ?releaseDate .
  BIND(YEAR(?releaseDate) AS ?year)
}

args.sparql:
SELECT ?film ?studio ?boxOffice WHERE {
  ?film wdt:P31 wd:Q11424;  # instance of film
         wdt:P577 ?releaseDate;
         wdt:P275 ?studio;
         wdt:P2253 ?boxOffice.
  FILTER(YEAR(?releaseDate) = 1957).
  ?boxOffice a wikibase:Quantity.
  ?boxOffice wikibase:quantityAmount ?amount.
  FILTER(abs(?amount - 15000000) < 1000000).
  ?boxOffice wikibase:quantityUnit wd:Q24303.
}

SELECT ?year WHERE {
  wd:Q1344202 wdt:P577 ?releaseDate.
  BIND(YEAR(?releaseDate) AS ?year)
}
